// Auto-generated: slim ZORDAQ emblem (134x220 PNG, ~18KB) for server-side PDF payslips.
// Source: public/zordaq-auto-slim.png (derived from public/zordaq-auto.png via sharp).
// Embedded as base64 because (1) Vercel does not bundle /public into serverless function
// output, and (2) the pdfkit *standalone* build stubs out 'fs', so doc.image() must be given
// a data: URI (it base64-decodes that in-memory) rather than a file path or raw Buffer.
export const ZORDAQ_LOGO_PNG_BASE64 =
  '';

export const ZORDAQ_LOGO_DATA_URI = `data:image/png;base64,${ZORDAQ_LOGO_PNG_BASE64}`;
